// Indian Government Standard Invoice Numbering
// Generates sequential invoice numbers with financial year format

import { getScopedStorageKey, getCurrentCompanyId } from './authUtils'
import { db, isFirebaseReady } from '../services/firebase'
import { isDeviceOnline } from '../services/offlineSyncService'
import { doc, runTransaction, serverTimestamp } from 'firebase/firestore'

const INVOICE_STORAGE_KEY = 'thisai_crm_invoices'

const getInvoiceStorageKey = () => getScopedStorageKey(INVOICE_STORAGE_KEY, 'company')

const getSequenceStorageKey = (financialYear: string, prefix: string) =>
  getScopedStorageKey(`invoice_seq_${prefix}_${financialYear}`, 'auto')

const getSequenceInitKey = (financialYear: string, prefix: string) =>
  getScopedStorageKey(`invoice_seq_init_${prefix}_${financialYear}`, 'auto')

const getSequenceEmptyResetKey = (financialYear: string, prefix: string) =>
  getScopedStorageKey(`invoice_seq_empty_reset_${prefix}_${financialYear}`, 'auto')

const getSequenceDocId = (companyId: string, prefix: string, financialYear: string) =>
  `seq_${companyId}_${prefix}_${financialYear}`

interface SequenceState {
  storageKey: string
  initKey: string
  emptyResetKey: string
  currentSequence: number
  maxSequence: number
  nextSequence: number
  shouldResetEmpty: boolean
  shouldInit: boolean
}

const getMaxSequenceFromStoredInvoices = (financialYear: string, prefix: string): number => {
  try {
    const stored = localStorage.getItem(getInvoiceStorageKey())
    if (!stored) return 0
    const invoices = JSON.parse(stored)
    if (!Array.isArray(invoices)) return 0

    let maxSequence = 0
    invoices.forEach((invoice: any) => {
      const invoiceNumber = invoice?.invoiceNumber
      if (!invoiceNumber || typeof invoiceNumber !== 'string') return
      if (!invoiceNumber.startsWith(`${prefix}/${financialYear}/`)) return
      const parts = invoiceNumber.split('/')
      if (parts.length !== 3) return
      const seq = parseInt(parts[2], 10)
      if (!Number.isNaN(seq) && seq > maxSequence) {
        maxSequence = seq
      }
    })
    return maxSequence
  } catch (error) {
    console.error('Error reading invoices for sequence seed:', error)
    return 0
  }
}

const getSequenceState = (financialYear: string, prefix: string): SequenceState => {
  const storageKey = getSequenceStorageKey(financialYear, prefix)
  const initKey = getSequenceInitKey(financialYear, prefix)
  const emptyResetKey = getSequenceEmptyResetKey(financialYear, prefix)

  const stored = localStorage.getItem(storageKey)
  const storedSequence = stored ? parseInt(stored, 10) : 0
  const storedSequenceValid = stored !== null && !Number.isNaN(storedSequence)

  let currentSequence = storedSequenceValid ? storedSequence : 0
  const maxSequence = getMaxSequenceFromStoredInvoices(financialYear, prefix)
  const hasEmptyReset = localStorage.getItem(emptyResetKey) === 'true'
  const isInitialized = localStorage.getItem(initKey) === 'true'

  let shouldResetEmpty = false
  if (maxSequence === 0 && currentSequence > 0 && !hasEmptyReset) {
    currentSequence = 0
    shouldResetEmpty = true
  }

  const shouldInit = !isInitialized
  if (shouldInit) {
    currentSequence = Math.max(currentSequence, maxSequence)
  } else if (!storedSequenceValid || currentSequence < maxSequence) {
    currentSequence = maxSequence
  }

  const nextSequence = currentSequence + 1

  return {
    storageKey,
    initKey,
    emptyResetKey,
    currentSequence,
    maxSequence,
    nextSequence,
    shouldResetEmpty,
    shouldInit
  }
}

/**
 * Get current Indian financial year
 * Financial year runs from April 1 to March 31
 * Returns format: "2024-25" for FY 2024-2025
 */
export function getCurrentFinancialYear(): string {
  const now = new Date()
  const currentYear = now.getFullYear()
  const currentMonth = now.getMonth() + 1 // JavaScript months are 0-indexed

  // If month is Jan-Mar (1-3), financial year is previous year to current year
  // If month is Apr-Dec (4-12), financial year is current year to next year
  if (currentMonth >= 4) {
    // Apr-Dec: FY is current year to next year
    const nextYear = (currentYear + 1).toString().slice(-2)
    return `${currentYear}-${nextYear}`
  } else {
    // Jan-Mar: FY is previous year to current year
    const prevYear = currentYear - 1
    const currYearShort = currentYear.toString().slice(-2)
    return `${prevYear}-${currYearShort}`
  }
}

/**
 * Get the next invoice sequence number for the current financial year
 * Stores counters in localStorage by financial year
 */
export function getNextInvoiceSequence(financialYear: string, prefix: string = 'INV'): number {
  try {
    const state = getSequenceState(financialYear, prefix)

    if (state.shouldResetEmpty) {
      localStorage.setItem(state.emptyResetKey, 'true')
    }
    if (state.shouldInit) {
      localStorage.setItem(state.initKey, 'true')
    }

    // Save the new sequence number
    localStorage.setItem(state.storageKey, state.nextSequence.toString())

    return state.nextSequence
  } catch (error) {
    console.error('Error managing invoice sequence:', error)
    // Fallback to timestamp-based unique number
    return Date.now() % 10000
  }
}

/**
 * Get the next invoice sequence number without incrementing
 */
export function peekNextInvoiceSequence(financialYear: string, prefix: string = 'INV'): number {
  try {
    const state = getSequenceState(financialYear, prefix)
    return state.nextSequence
  } catch (error) {
    console.error('Error reading invoice sequence:', error)
    return Date.now() % 10000
  }
}

const formatInvoiceNumber = (
  prefix: string,
  financialYear: string,
  sequence: number,
  paddingLength: number
): string => {
  const paddedSequence = sequence.toString().padStart(paddingLength, '0')
  return `${prefix}/${financialYear}/${paddedSequence}`
}

/**
 * Generate Indian government standard invoice number
 * Format: INV/2024-25/001
 *
 * @param prefix - Invoice prefix (default: "INV")
 * @param paddingLength - Number of digits for sequence (default: 3)
 * @returns Formatted invoice number
 *
 * Examples:
 * - INV/2024-25/001
 * - INV/2024-25/002
 * - INV/2024-25/999
 * - INV/2024-25/1000 (auto-expands beyond padding)
 */
export function generateIndianInvoiceNumber(
  prefix: string = 'INV',
  paddingLength: number = 3
): string {
  const financialYear = getCurrentFinancialYear()
  const sequence = getNextInvoiceSequence(financialYear, prefix)
  return formatInvoiceNumber(prefix, financialYear, sequence, paddingLength)
}

/**
 * Preview the next invoice number without incrementing
 */
export function previewIndianInvoiceNumber(
  prefix: string = 'INV',
  paddingLength: number = 3
): string {
  const financialYear = getCurrentFinancialYear()
  const sequence = peekNextInvoiceSequence(financialYear, prefix)
  return formatInvoiceNumber(prefix, financialYear, sequence, paddingLength)
}

/**
 * Get and commit the next invoice number.
 * Uses Firebase transaction when online to avoid duplicates across devices.
 * Falls back to local sequence when offline/unconfigured.
 */
export async function getCommittedIndianInvoiceNumber(
  prefix: string = 'INV',
  paddingLength: number = 3
): Promise<string> {
  const financialYear = getCurrentFinancialYear()
  const companyId = getCurrentCompanyId()

  if (companyId && isFirebaseReady() && isDeviceOnline() && db) {
    try {
      const docId = getSequenceDocId(companyId, prefix, financialYear)
      const docRef = doc(db, 'serial_sequences', docId)

      const nextSequence = await runTransaction(db, async (transaction) => {
        const snapshot = await transaction.get(docRef)
        const current = snapshot.exists() ? Number(snapshot.data()?.current || 0) : 0
        const next = current + 1
        transaction.set(docRef, {
          companyId,
          prefix,
          financialYear,
          current: next,
          updatedAt: serverTimestamp()
        }, { merge: true })
        return next
      })

      const invoiceNumber = formatInvoiceNumber(prefix, financialYear, nextSequence, paddingLength)
      // Sync local sequence to the committed value so previews match
      commitIndianInvoiceNumber(invoiceNumber, prefix, paddingLength)
      return invoiceNumber
    } catch (error) {
      console.warn('Failed to commit invoice sequence via Firebase, falling back to local:', error)
    }
  }

  return generateIndianInvoiceNumber(prefix, paddingLength)
}

/**
 * Commit an invoice number to the sequence counter (without generating a new one)
 */
export function commitIndianInvoiceNumber(
  invoiceNumber: string | undefined,
  fallbackPrefix: string = 'INV',
  paddingLength: number = 3
): string {
  if (invoiceNumber && isValidIndianInvoiceNumber(invoiceNumber)) {
    const parsed = parseInvoiceNumber(invoiceNumber)
    if (parsed) {
      try {
        const state = getSequenceState(parsed.financialYear, parsed.prefix)
        const committedSequence = Math.max(parsed.sequence, state.currentSequence)

        if (state.shouldResetEmpty) {
          localStorage.setItem(state.emptyResetKey, 'true')
        }
        if (state.shouldInit) {
          localStorage.setItem(state.initKey, 'true')
        }

        localStorage.setItem(state.storageKey, committedSequence.toString())
        return invoiceNumber
      } catch (error) {
        console.error('Error committing invoice sequence:', error)
      }
    }
  }

  return generateIndianInvoiceNumber(fallbackPrefix, paddingLength)
}

/**
 * Reset invoice sequence for a given financial year
 * Useful for testing or manual reset
 */
export function resetInvoiceSequence(financialYear?: string, prefix: string = 'INV'): void {
  const fy = financialYear || getCurrentFinancialYear()
  const storageKey = getSequenceStorageKey(fy, prefix)
  localStorage.setItem(storageKey, '0')
  console.log(`Invoice sequence reset for FY ${fy} (${prefix})`)
}

/**
 * Get current invoice sequence without incrementing
 */
export function getCurrentInvoiceSequence(financialYear?: string, prefix: string = 'INV'): number {
  const fy = financialYear || getCurrentFinancialYear()
  const storageKey = getSequenceStorageKey(fy, prefix)

  try {
    const stored = localStorage.getItem(storageKey)
    return stored ? parseInt(stored, 10) : 0
  } catch (error) {
    console.error('Error reading invoice sequence:', error)
    return 0
  }
}

/**
 * Validate invoice number format
 */
export function isValidIndianInvoiceNumber(invoiceNumber: string): boolean {
  // Format: PREFIX/YYYY-YY/NNN
  const pattern = /^[A-Z]+\/\d{4}-\d{2}\/\d+$/
  return pattern.test(invoiceNumber)
}

/**
 * Parse invoice number components
 */
export function parseInvoiceNumber(invoiceNumber: string): {
  prefix: string
  financialYear: string
  sequence: number
} | null {
  if (!isValidIndianInvoiceNumber(invoiceNumber)) {
    return null
  }

  const parts = invoiceNumber.split('/')
  return {
    prefix: parts[0],
    financialYear: parts[1],
    sequence: parseInt(parts[2], 10)
  }
}
